1	/**
2	 * OKKI 一键同步脚本
3	 *
4	 * 自动检测浏览器状态 → 登录 → 导航TM → 提取会话元数据 → 增量拉消息
5	 *
6	 * 用法：node scripts/sync_okki.js
7	 *
8	 * 适用所有场景：
9	 * - 刚开机/Chrome没开/没登录 → 自动启动Chrome → 等你登录 → 继续
10	 * - Chrome开着+已登录+在TM页 → 直接抓取
11	 * - Chrome开着但不在TM页 → 自动导航
12	 */
13	
14	const { chromium } = require('playwright');
15	const fs = require('fs');
16	const path = require('path');
17	const http = require('http');
18	
19	const PROFILE = 'C:\\Users\\Administrator\\AppData\\Local\\Google\\Chrome\\User Data\\Profile 4';
20	const DATA_DIR = path.join(__dirname, '..', 'data');
21	const CHAT_DIR = path.join(DATA_DIR, 'chat_history');
22	const CDP_URL = 'http://localhost:9222';
23	const MSG_COUNT = 50;
24	const MAX_PAGES = 20;
25	
26	// ===================== 工具函数 =====================
27	
28	function ts() { return new Date().toISOString().replace(/[:.]/g, '-').slice(0, 19); }
29	function log(msg) { console.log(`[${new Date().toLocaleTimeString()}] ${msg}`); }
30	function sleep(ms) { return new Promise(r => setTimeout(r, ms)); }
31	
32	function sanitizeFilename(cid) {
33	  return cid.replace(/[<>:"/\\|?*#@]/g, '_').substring(0, 200);
34	}
35	
36	// ===================== CDP 端口检测 =====================
37	
38	function checkCdpPort() {
39	  return new Promise((resolve) => {
40	    const req = http.get('http://127.0.0.1:9222/json/version', (res) => {
41	      let data = '';
42	      res.on('data', c => data += c);
43	      res.on('end', () => {
44	        try {
45	          const json = JSON.parse(data);
46	          resolve(!!json.webSocketDebuggerUrl);
47	        } catch (e) { resolve(false); }
48	      });
49	    });
50	    req.on('error', () => resolve(false));
51	    req.setTimeout(2000, () => { req.destroy(); resolve(false); });
52	  });
53	}
54	
55	// ===================== 主流程 =====================
56	
57	async function main() {
58	  let browser;
59	  let page;
60	  let useCdp = false;
61	
62	  // ---- Step 1: 启动/连接浏览器 ----
63	  const cdpAvailable = await checkCdpPort();
64	  if (cdpAvailable) {
65	    log('检测到 CDP 端口，尝试连接已有 Chrome...');
66	    try {
67	      browser = await chromium.connectOverCDP(CDP_URL);
68	      const pages = browser.contexts()[0]?.pages() || [];
69	      page = pages.find(p => p.url().includes('xiaoman') || p.url().includes('onetalk'));
70	      if (!page) {
71	        page = await browser.contexts()[0].newPage();
72	      }
73	      useCdp = true;
74	      log(`CDP 已连接。当前页面: ${page.url()}`);
75	    } catch (e) {
76	      log(`CDP 连接失败: ${e.message}，改用独立启动模式`);
77	    }
78	  }
79	
80	  if (!browser) {
81	    log('启动 Chrome (Profile 4)...');
82	    browser = await chromium.launchPersistentContext(PROFILE, {
83	      channel: 'chrome',
84	      headless: false,
85	      viewport: { width: 1440, height: 900 },
86	      args: ['--remote-debugging-port=9222'],
87	    });
88	    page = await browser.newPage();
89	    log('Chrome 已启动');
90	  }
91	
92	  // ---- Step 2: 导航到 OKKI + 登录检测 ----
93	  const currentUrl = page.url();
94	  if (!currentUrl.includes('xiaoman') && !currentUrl.includes('onetalk') && !currentUrl.includes('alibaba')) {
95	    log('导航到 crm.xiaoman.cn...');
96	    await page.goto('https://crm.xiaoman.cn/', { waitUntil: 'domcontentloaded', timeout: 30000 });
97	  }
98	
99	  // 检测登录状态
100	  let loginUrl = page.url();
101	  if (loginUrl.includes('login.xiaoman.cn') || loginUrl.includes('login.alibaba.com')) {
102	    log('');
103	    log('========================================');
104	    log('  请在浏览器中登录 OKKI (小满)');
105	    log('  登录后脚本自动继续...');
106	    log('========================================');
107	    log('');
108	
109	    const startTime = Date.now();
110	    const maxWait = 5 * 60 * 1000;
111	    while (Date.now() - startTime < maxWait) {
112	      const url = page.url();
113	      if (!url.includes('login.xiaoman.cn') && !url.includes('login.alibaba.com') && url.includes('crm.xiaoman.cn')) {
114	        log('登录成功！');
115	        break;
116	      }
117	      await sleep(2000);
118	    }
119	    if (page.url().includes('login')) {
120	      log('超时：未检测到登录。退出。');
121	      await browser.close();
122	      process.exit(1);
123	    }
124	  } else {
125	    log('已登录状态');
126	  }
127	
128	  // ---- Step 3: 导航到 TM 消息页面 ----
129	  log('导航到 TM 消息页...');
130	  await page.goto('https://crm.xiaoman.cn/im/', { waitUntil: 'domcontentloaded', timeout: 30000 }).catch(() => {});
131	  await sleep(3000);
132	
133	  // 可能需要点击侧边栏进入 TM（OKKI 的 /im/ 可能只显示外壳，onetalk 在 iframe 里）
134	  log(`当前 URL: ${page.url()}`);
135	
136	  // ---- Step 4: 等待 onetalk iframe + 数据就绪 ----
137	  log('等待 onetalk iframe 加载...');
138	
139	  // 递归查找 onetalk 页面（可能在嵌套 iframe 中）
140	  function findOnetalkFrame(pageOrFrame) {
141	    const frames = pageOrFrame.frames ? pageOrFrame.frames() : (pageOrFrame.childFrames ? pageOrFrame.childFrames() : []);
142	    for (const f of frames) {
143	      const url = f.url();
144	      // 真正的 onetalk PWA 页面，不是 OKKI 外壳
145	      if (url.startsWith('https://onetalk.alibaba.com/')) return f;
146	      // 递归查找
147	      const found = findOnetalkFrame(f);
148	      if (found) return found;
149	    }
150	    return null;
151	  }
152	
153	  let iframePage = null;
154	  for (let attempt = 0; attempt < 30; attempt++) {
155	    iframePage = findOnetalkFrame(page);
156	    if (iframePage) {
157	      log(`onetalk iframe 已找到 (尝试 ${attempt + 1}): ${iframePage.url().slice(0, 100)}`);
158	      break;
159	    }
160	    if (attempt === 0) {
161	      const bodyText = await page.evaluate(() => document.body.innerText?.slice(0, 500)).catch(() => '');
162	      log(`  页面预览: ${bodyText.slice(0, 200)}`);
163	      // 检查是否在 OKKI 外壳中
164	      const allFrames = page.frames();
165	      log(`  当前 ${allFrames.length} 个 frame:`);
166	      for (const f of allFrames) {
167	        log(`    ${f.url().slice(0, 120)}`);
168	      }
169	    }
170	    await sleep(2000);
171	  }
172	
173	  if (!iframePage) {
174	    log('iframe 未找到。请确认：');
175	    log('  1. 已退出手机阿里卖家');
176	    log('  2. OKKI TM 面板不是 "Click to retry" 状态');
177	    log('  3. TM 面板中能看到会话列表');
178	    log('');
179	    log('脚本保持运行。完成上述操作后回车继续...');
180	    await new Promise(() => {});
181	  }
182	
183	  // ---- Step 4.5: 滚动加载全部会话 ----
184	  // 虚拟列表只渲染可见窗口，不滚动会漏掉窗口外的新客户/老客户
185	  log('滚动加载全部会话...');
186	  let initialCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
187	  log(`  初始会话数: ${initialCount}`);
188	
189	  let lastCount = initialCount;
190	  let unchangedRounds = 0;
191	
192	  for (let round = 0; round < 50; round++) {
193	    const scrollResult = await iframePage.evaluate(() => {
194	      let best = null;
195	      let bestScore = 0;
196	      for (const el of document.querySelectorAll('div')) {
197	        const childCount = el.children.length;
198	        const scrollDiff = el.scrollHeight - el.clientHeight;
199	        if (childCount > 20 && scrollDiff > 200) {
200	          const score = childCount + scrollDiff;
201	          if (score > bestScore) { best = el; bestScore = score; }
202	        }
203	      }
204	      if (!best) return { done: true, count: (window.__conversationListFullData__ || []).length };
205	      const before = (window.__conversationListFullData__ || []).length;
206	      best.scrollTop = best.scrollHeight;
207	      return { done: false, before, scrollH: best.scrollHeight, clientH: best.clientHeight };
208	    });
209	
210	    if (scrollResult.done) { log('  找不到合适的滚动容器'); break; }
211	    await sleep(2000);
212	
213	    const newCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
214	    if (round % 3 === 0 || newCount !== lastCount) {
215	      log(`  第${round+1}轮: ${scrollResult.before} → ${newCount}`);
216	    }
217	
218	    if (newCount === lastCount) {
219	      unchangedRounds++;
220	      if (unchangedRounds >= 3) { log('  数据已稳定，滚动完成'); break; }
221	    } else {
222	      unchangedRounds = 0;
223	    }
224	    lastCount = newCount;
225	  }
226	
227	  const finalCount = await iframePage.evaluate(() => (window.__conversationListFullData__ || []).length);
228	  log(`  滚动后会话总数: ${finalCount} (初始: ${initialCount})`);
229	
230	  // ---- Step 5: 提取会话列表（带重试） ----
231	  log('提取会话元数据...');
232	  let convData = null;
233	  for (let attempt = 0; attempt < 20; attempt++) {
234	    convData = await iframePage.evaluate(() => {
235	      const convs = window.__conversationListFullData__;
236	      if (!convs || !Array.isArray(convs)) return { error: 'no __conversationListFullData__', type: typeof convs, count: 0 };
237	      return {
238	        count: convs.length,
239	        list: convs.map(c => ({
240	          cid: c.cid,
241	          name: c.name,
242	          loginId: c.loginId,
243	          aliId: c.aliId,
244	          accountId: c.accountId,
245	          companyName: c.companyName,
246	          country: c.country,
247	          level: c.level,
248	          serviceType: c.serviceType,
249	          conversationType: c.conversationType,
250	          unreadCount: c.unreadCount,
251	          stayTop: c.stayTop,
252	          lastContactTime: c.lastContactTime,
253	          lastContactTimeLong: c.lastContactTimeLong,
254	          createAt: c.createAt,
255	          tagInfo: c.tagInfo,
256	          available: c.available,
257	          complianceCountryCode: c.complianceCountryCode,
258	          latestMessage: c.latestMessage ? {
259	            content: c.latestMessage.content,
260	            messageType: c.latestMessage.messageType,
261	            messageId: c.latestMessage.messageId,
262	            gmtChat: c.latestMessage.gmtChat,
263	            contactRead: c.latestMessage.contactRead,
264	          } : null,
265	        })),
266	      };
267	    }).catch(e => ({ error: e.message, count: 0 }));
268	
269	    if (!convData.error && convData.count > 0) {
270	      log(`提取成功: ${convData.count} 个会话 (尝试 ${attempt + 1})`);
271	      break;
272	    }
273	    if (attempt === 0) {
274	      log(`  等待 TM 数据加载 (${convData.error || '空数据'})...`);
275	    }
276	    await sleep(2000);
277	  }
278	
279	  if (!convData || convData.error || convData.count === 0) {
280	    log(`提取失败: ${convData?.error || '无数据'}`);
281	    log('TM 面板可能未正常加载。请确认能看到会话列表后重新运行脚本。');
282	    await browser.close();
283	    process.exit(1);
284	  }
285	
286	  // 展平结果
287	  const convList = convData.list;
288	  const totalCount = convData.count;
289	
290	  log(`提取到 ${totalCount} 个会话`);
291	
292	  // ---- Step 6: 保存最新元数据 ----
293	  const latestMeta = {
294	    exportedAt: new Date().toISOString(),
295	    total: totalCount,
296	    conversations: convList,
297	  };
298	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
299	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
300	  log(`元数据已保存: tm_conversations_latest.json (${totalCount} 会话)`);
301	
302	  // ---- Step 7: Diff 找出变化的会话 ----
303	  log('对比上次数据...');
304	  let oldMeta = null;
305	  const oldPath = path.join(DATA_DIR, 'tm_conversations_full.json');
306	  if (fs.existsSync(oldPath)) {
307	    oldMeta = JSON.parse(fs.readFileSync(oldPath, 'utf-8'));
308	  }
309	
310	  const changed = [];
311	  const oldMap = new Map();
312	  if (oldMeta?.conversations) {
313	    for (const c of oldMeta.conversations) {
314	      oldMap.set(c.cid, c);
315	    }
316	  }
317	
318	  for (const c of convList) {
319	    const old = oldMap.get(c.cid);
320	    if (!old) {
321	      // 新会话
322	      changed.push({ cid: c.cid, name: c.name, reason: '新会话', oldLmId: null, newLmId: c.latestMessage?.messageId });
323	      continue;
324	    }
325	    const oldLmId = old.latestMessage?.messageId;
326	    const newLmId = c.latestMessage?.messageId;
327	    const oldLct = old.lastContactTime || 0;
328	    const newLct = c.lastContactTime || 0;
329	
330	    if (oldLmId !== newLmId || newLct > oldLct) {
331	      const reason = oldLmId !== newLmId ? '消息更新' : '时间更新';
332	      changed.push({ cid: c.cid, name: c.name, reason, oldLmId, newLmId });
333	    }
334	  }
335	
336	  log(`变化会话: ${changed.length} 个`);
337	  if (changed.length > 0) {
338	    for (const ch of changed.slice(0, 15)) {
339	      log(`  ${ch.reason}: ${ch.name}`);
340	    }
341	    if (changed.length > 15) log(`  ... 共 ${changed.length} 个`);
342	  }
343	
344	  // ---- Step 8: 增量拉取聊天历史 ----
345	  if (changed.length === 0) {
346	    log('无变化，无需拉取聊天历史。同步完成。');
347	    computePreComputed(convList);
348	    printSummary(convList, changed);
349	    log('浏览器保持打开，供后续脚本使用');
350	    return;
351	  }
352	
353	  log('');
354	  log(`开始增量拉取 ${changed.length} 个会话的聊天历史...`);
355	
356	  // 获取 CDP session
357	  let cdpClient;
358	  let iframeSessionId;
359	
360	  if (!useCdp) {
361	    // Playwright 启动模式: 需要通过 CDP 访问 iframe
362	    cdpClient = await page.context().newCDPSession(page);
363	    const targets = await cdpClient.send('Target.getTargets');
364	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
365	    if (ot) {
366	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
367	      iframeSessionId = attached.sessionId;
368	      log(`CDP attached to onetalk iframe: ${ot.url.slice(0, 80)}`);
369	    } else {
370	      log('警告: 未找到 onetalk iframe target，尝试用 page.frames() 方式...');
371	    }
372	  } else {
373	    // CDP 连接模式: page 已经是 CDP 连接的
374	    cdpClient = await page.context().newCDPSession(page);
375	    const targets = await cdpClient.send('Target.getTargets');
376	    const ot = targets.targetInfos.find(t => t.url.includes('onetalk') && t.type === 'iframe');
377	    if (!ot) {
378	      // 检查 page 本身是否是 onetalk
379	      if (page.url().includes('onetalk')) {
380	        iframeSessionId = undefined; // page 本身就是 onetalk
381	        log('当前页面就是 onetalk');
382	      } else {
383	        log('警告: 未找到 onetalk target');
384	      }
385	    } else {
386	      const attached = await cdpClient.send('Target.attachToTarget', { targetId: ot.targetId, flatten: false });
387	      iframeSessionId = attached.sessionId;
388	      log(`CDP attached to onetalk iframe`);
389	    }
390	  }
391	
392	  // 安装 LWP 收发器
393	  if (iframeSessionId || page.url().includes('onetalk')) {
394	    log('安装 LWP 收发器...');
395	    await installLwp(cdpClient, iframeSessionId);
396	    await sleep(3000);
397	
398	    // 确认 WS 已捕获
399	    const wsState = await evalInIframe(cdpClient, iframeSessionId, 10,
400	      `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
401	    );
402	    log(`WS 状态: ${JSON.stringify(wsState)}`);
403	
404	    if (!wsState?.ws) {
405	      log('等待 WebSocket 连接...');
406	      await sleep(15000);
407	      const wsState2 = await evalInIframe(cdpClient, iframeSessionId, 11,
408	        `(function(){return JSON.stringify({ws:!!window.__lwpWs,url:window.__lwpWs?window.__lwpWs.url:null})})()`
409	      );
410	      log(`WS 状态(重试): ${JSON.stringify(wsState2)}`);
411	    }
412	
413	    // 拉取消息
414	    let pulled = 0;
415	    let errors = 0;
416	    let totalNewMsgs = 0;
417	    let msgIdCounter = 100;
418	
419	    for (let i = 0; i < changed.length; i++) {
420	      const conv = changed[i];
421	      try {
422	        const allMessages = [];
423	        let cursor = 9007199254740991;
424	        let pageNum = 0;
425	
426	        while (pageNum < MAX_PAGES) {
427	          const msgId = msgIdCounter++;
428	          const raw = await evalInIframe(cdpClient, iframeSessionId, msgId,
429	            `(async function() {
430	              try {
431	                var result = await window.__lwpRequest('/r/MessageManager/listUserMessages', ['${conv.cid}', false, ${cursor}, ${MSG_COUNT}, false]);
432	                return JSON.stringify(result);
433	              } catch(e) {
434	                return JSON.stringify({ __error: e.message });
435	              }
436	            })()`,
437	            true
438	          );
439	
440	          await sleep(1500);
441	
442	          if (!raw || raw.__error) {
443	            if (raw?.__error === 'timeout') { log(`  [${conv.name}] LWP超时`); }
444	            break;
445	          }
446	
447	          let response;
448	          try { response = typeof raw === 'string' ? JSON.parse(raw) : raw; } catch (e) { break; }
449	          if (response.code !== 200) break;
450	
451	          const body = response.body;
452	          if (!body?.userMessageModels || body.userMessageModels.length === 0) break;
453	
454	          allMessages.push(...body.userMessageModels);
455	
456	          if (body.userMessageModels.length < MSG_COUNT || !body.nextCursor) break;
457	          cursor = body.nextCursor;
458	          pageNum++;
459	        }
460	
461	        // 保存
462	        const safeName = sanitizeFilename(conv.cid);
463	        const output = {
464	          cid: conv.cid,
465	          name: conv.name,
466	          fetchedAt: new Date().toISOString(),
467	          totalMessages: allMessages.length,
468	          messages: allMessages,
469	        };
470	        fs.writeFileSync(path.join(CHAT_DIR, safeName + '.json'), JSON.stringify(output, null, 2));
471	        pulled++;
472	        totalNewMsgs += allMessages.length;
473	        if (allMessages.length > 0) {
474	          log(`  [${i+1}/${changed.length}] ${conv.name}: ${allMessages.length} 条消息`);
475	        }
476	      } catch (e) {
477	        errors++;
478	        if (errors <= 5) log(`  [${conv.name}] 错误: ${e.message}`);
479	      }
480	    }
481	
482	    log(`拉取完成: ${pulled} 个会话, ${totalNewMsgs} 条消息, ${errors} 个错误`);
483	  } else {
484	    log('');
485	    log('========================================');
486	    log('  ❌ LWP 拉取失败：无法访问 onetalk iframe');
487	    log('  请确认：');
488	    log('  1. Chrome 已打开 OKKI TM 面板');
489	    log('  2. TM 面板中能看到会话列表');
490	    log('  3. 没有其他程序占用 CDP 端口 9222');
491	    log('========================================');
492	    log('');
493	    log('脚本退出。请排查后重新运行。');
494	    process.exit(1);
495	  }
496	
497	  // ---- Step 9: 预计算 + 归档 + 输出摘要 ----
498	  computePreComputed(convList);
499	  // 归档：将本次最新数据作为下次 diff 的基线
500	  const fullPath = path.join(DATA_DIR, 'tm_conversations_full.json');
501	  fs.writeFileSync(fullPath, JSON.stringify(latestMeta, null, 2));
502	  log('已归档基线: tm_conversations_full.json');
503	  printSummary(convList, changed);
504	  log('同步完成。浏览器保持打开，供后续脚本使用');
505	}
