619	function computePreComputed(convList) {
620	  const now = Date.now();
621	  const chatDir = path.join(DATA_DIR, 'chat_history');
622	
623	  for (const c of convList) {
624	    c.preComputed = {};
625	
626	    // 1. 是否未读
627	    c.preComputed.isUnread = (c.unreadCount || 0) > 0;
628	
629	    // 2. 距上次联系天数
630	    const lct = c.lastContactTimeLong || c.lastContactTime || 0;
631	    c.preComputed.daysSinceLastContact = lct > 0 ? Math.floor((now - lct) / 86400000) : null;
632	
633	    // 3. latestMessage 是否是系统消息
634	    const lmContent = c.latestMessage?.content || '';
635	    c.preComputed.isLatestMessageSystem = false;
636	    if (lmContent) {
637	      for (const pat of SYSTEM_MSG_PATTERNS) {
638	        if (lmContent.includes(pat)) {
639	          c.preComputed.isLatestMessageSystem = true;
640	          break;
641	        }
642	      }
643	    }
644	
645	    // 4. 是否有 chat_history 文件
646	    const fileName = sanitizeFilename(c.cid) + '.json';
647	    const filePath = path.join(chatDir, fileName);
648	    c.preComputed.hasChatHistoryFile = fs.existsSync(filePath);
649	
650	    // 5. 是否有真实消息（chat_history 文件中存在非系统消息）
651	    c.preComputed.hasRealMessages = false;
652	    if (c.preComputed.hasChatHistoryFile) {
653	      try {
654	        const data = JSON.parse(fs.readFileSync(filePath, 'utf-8'));
655	        for (const msg of (data.messages || [])) {
656	          const content = msg.message?.content?.text?.content || '';
657	          if (!content) continue;
658	          let isSys = false;
659	          for (const pat of SYSTEM_MSG_PATTERNS) {
660	            if (content.includes(pat)) { isSys = true; break; }
661	          }
662	          if (!isSys) {
663	            c.preComputed.hasRealMessages = true;
664	            break;
665	          }
666	        }
667	      } catch (e) {}
668	    }
669	  }
670	
671	  // 重新保存带 preComputed 的元数据
672	  const metaPath = path.join(DATA_DIR, 'tm_conversations_latest.json');
673	  const latestMeta = {
674	    exportedAt: new Date().toISOString(),
675	    total: convList.length,
676	    conversations: convList,
677	  };
678	  fs.writeFileSync(metaPath, JSON.stringify(latestMeta, null, 2));
679	  log(`preComputed 已计算，元数据已更新`);
680	}
